CODE_EXAMPLE:
class Report {
    private String title;
    private Date created;

    public String generate() {
        String header = buildHeader();
        String body = buildBody();
        return header + body;
    }

    private String buildHeader() { return title; }

    private String buildBody()   { return "body"; }
}

UNIT_TEST_EXAMPLE:
@Test
public void generate_combinesHeaderAndBody() {
    Report report = new Report("Q1 Summary", new Date());
    String result = report.generate();
    assertTrue(result.startsWith("Q1 Summary"));
    assertTrue(result.contains("body"));
}
